import React from 'react';
import { LucideIcon, TrendingUp, TrendingDown } from 'lucide-react';

interface StatCardProps {
  title: string;
  value: number | string;
  icon: LucideIcon;
  trend?: number;
  type?: 'primary' | 'success' | 'warning' | 'info' | 'danger';
  prefix?: string;
  suffix?: string;
}

const TYPE_COLORS = {
  primary: { bg: 'bg-primary-50', text: 'text-primary-600', icon: 'bg-primary-600' },
  success: { bg: 'bg-emerald-50', text: 'text-emerald-600', icon: 'bg-emerald-600' },
  warning: { bg: 'bg-amber-50', text: 'text-amber-600', icon: 'bg-amber-600' },
  info: { bg: 'bg-sky-50', text: 'text-sky-600', icon: 'bg-sky-600' },
  danger: { bg: 'bg-red-50', text: 'text-red-600', icon: 'bg-red-600' },
}

export const StatCard: React.FC<StatCardProps> = ({
  title, value, icon: Icon, trend, type = 'primary', prefix = '', suffix = '',
}) => {
  const colors = TYPE_COLORS[type];
  const isPositive = (trend ?? 0) >= 0;
  const displayValue = typeof value === 'number' ? value.toLocaleString() : value;

  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 hover:shadow-md transition-shadow">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <p className="text-[12px] font-semibold text-gray-500 uppercase tracking-wide">{title}</p>
        <div className={`w-9 h-9 rounded-lg ${colors.icon} flex items-center justify-center`}>
          <Icon className="w-4 h-4 text-white" strokeWidth={2} />
        </div>
      </div>

      {/* Value */}
      <div className="flex items-baseline gap-1">
        {prefix && <span className={`text-sm font-semibold ${colors.text}`}>{prefix}</span>}
        <span className="text-2xl font-bold text-gray-900 tracking-tight">{displayValue}</span>
        {suffix && <span className="text-sm font-medium text-gray-400">{suffix}</span>}
      </div>

      {/* Trend */}
      {trend !== undefined && (
        <div className="flex items-center gap-1.5 mt-3">
          <div className={`flex items-center gap-0.5 text-[11px] font-semibold
            ${isPositive ? 'text-emerald-600' : 'text-red-500'}`}>
            {isPositive
              ? <TrendingUp className="w-3 h-3" />
              : <TrendingDown className="w-3 h-3" />
            }
            {Math.abs(trend).toFixed(1)}%
          </div>
          <span className="text-[11px] text-gray-400">จากเดือนก่อน</span>
        </div>
      )}
    </div>
  );
};